            return Q.delay(20).then(function () {
                queue.put(1);
            })
        })
        .then(function () {
            return Q.delay(20).then(function () {
                queue.put(2);
            })
        })
        .then(function () {
            return Q.delay(20).then(function () {
                queue.put(3);
            })
        })
        .done();

        return Q.try(function () {
            return queue.get()
            .then(function (value) {
                expect(value).toBe(1);
            });
        })
        .then(function () {
            return queue.get()
            .then(function (value) {
                expect(value).toBe(2);
            });
        })
        .then(function () {
            return queue.get()
            .then(function (value) {
                expect(value).toBe(3);
            });
        })

    });

    it("should be order agnostic", function () {
        var queue = Queue();

        Q.try(function () {
            return Q.delay(20).then(function () {
                queue.put(1);
            })
        })
        .then(function () {
            return Q.delay(20).then(function () {
                queue.put(2);
            })
        })
        .then(function () {
            return Q.delay(20).then(function () {
                queue.put(3);
            })
        })
        .done();

        return Q.all([
            queue.get()
            .then(function (value) {
                expect(value).toBe(1);
            }),
            queue.get()
            .then(function (value) {
                expect(value).toBe(2);
            }),
            queue.get()
            .then(function (value) {
                expect(value).toBe(3);
            })
        ]);
    });

    it("should close", function () {

        var queue = Queue();

        Q.try(function () {
            return Q.delay(20).then(function () {
                queue.put(1);
            })
        })
        .then(function () {
            return Q.delay(20).then(function () {
                queue.put(2);
            })
        })
        .then(function () {
            queue.close();
        })
        .done();

        return Q.try(function () {
            return queue.get()
            .then(function (value) {
                expect(value).toBe(1);
            });
        })
        .then(function () {
            return queue.get()
            .then(function (value) {
                expect(value).toBe(2);
            });
        })
        .then(function () {
            return queue.get()
            .then(function (value) {
                expect(false).toBe(true); // should not get here
            });
        })
        .catch(function (error) {
            expect(error.message).toBe("Can't get value from closed queue");
            return queue.get();
        })
        .catch(function (error) {
            expect(error.message).toBe("Can't get value from closed queue");
        })
        .then(function () {
            return queue.closed;
        })
        .then(function (error) {
            expect(error.message).toBe("Can't get value from closed queue");
        })
    });

    it("should close with alternate error", function () {

        var queue = Queue();
        queue.close(new Error("Alternate reason"));

        return Q.try(function () {
            return queue.get();
        })
        .catch(function (error) {
            expect(error.message).toBe("Alternate reason");
            return queue.get();
        })
        .catch(function (error) {
            expect(error.message).toBe("Alternate reason");
        })
        .then(function () {
            return queue.closed;
        })
        .then(function (error) {
            expect(error.message).toBe("Alternate reason");
        })
    });

